#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    bool isValidAfterTwoShifts(vector<int>& arr) {
        if (arr.size() & 1) return true;
        int start = 0, end = arr.size() - 1;
        while (start < end) {
            if (arr[start] == arr[end]) {
                start++;
                end--;
            } else {
                return false;
            }
        }
        return true;
    }
};
int main() {
    vector<int> arr;
    int n;
    cin >> n;
    arr.resize(n);
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    Solution s;
    cout << s.isValidAfterTwoShifts(arr) << endl;
    return 0;
}
